module top_module(
    input [3:0] A,
    input [3:0] B,
    input op,
    output reg [3:0] error_value
);always @(*) begin
        if (op == 1'b0) begin
            // subtraction
            error_value = A - B;
        end else begin
            // addition
            error_value = A + B;
        end
    end
endmodule
